-- 1. Half Dome
INSERT INTO validated_objectives (name, route, match_aliases, type, difficulty, description, summit_elevation_ft, total_gain_ft, distance_miles, duration_days, technical_grade, tags, target_scores, taglines, relevance_profiles, graduation_benchmarks, recommended_weeks, status) VALUES
('Half Dome', 'Mist Trail + Cables',   '{"half dome", "half dome mist trail", "half dome cables", "half dome yosemite"}', 'hike', 'intermediate', 'Iconic Yosemite summit via the Mist Trail and cable route. 14-16 mile day with 4,800ft gain and the famous cable section.', 8844, 4800, 14.5, 1, 'Class 2-3 (cables)', '["heavy-pack", "exposure", "endurance", "long-day"]',
'{"cardio":75,"strength":70,"climbing_technical":45,"flexibility":55}',
'{"cardio":"All-day hiking endurance engine","strength":"Leg power plus grip endurance","climbing_technical":"Cable confidence and exposure comfort","flexibility":"Hip and ankle mobility support"}',
'{"cardio":{"summary":"Half Dome demands exceptional hiking endurance for 14+ miles with nearly 5,000 feet of elevation gain. This is a long day requiring sustained aerobic capacity and the ability to maintain pace while fatigued.","keyComponents":["Sustained uphill hiking pace","Long-duration aerobic base","Elevation gain capacity","Late-day fatigue resistance","Loaded pack endurance","Heart rate control on climbs","Recovery between steep sections","Downhill impact tolerance","Multi-hour energy systems","Consistent pacing strategy"],"irrelevantComponents":["Sprint power","Anaerobic threshold intervals","Track running speed","Cycling-specific fitness","Swimming endurance","High-intensity intervals","Powerlifting cardio","Short burst capacity","Competition pacing","Race-day tactics"]},"strength":{"summary":"Primary strength demands are leg power for sustained uphill hiking and grip endurance for the cable section. Core stability supports heavy pack carry over long distances.","keyComponents":["Uphill hiking leg power","Grip endurance for cables","Loaded pack carry capacity","Single-leg stability","Calf and quad endurance","Core stability under load","Knee joint stability","Hip flexor strength","Postural endurance","Late-day strength maintenance"],"irrelevantComponents":["Upper body pressing power","Olympic lifting capacity","Bench press strength","Overhead pressing","Back squat max","Explosive jumping power","Arm wrestling strength","Heavy deadlift capacity","Powerlifting totals","Gymnastic strength skills"]},"climbing_technical":{"summary":"The cables section requires basic scrambling skills and comfort with exposure. This is low-grade technical terrain but psychologically demanding with significant consequences for mistakes.","keyComponents":["Cable route technique","Exposure comfort","Basic scrambling skills","Three-point contact discipline","Route reading on rock","Movement efficiency on granite","Glove use technique","Crowd management skills","Weather assessment","Risk evaluation"],"irrelevantComponents":["Advanced rope skills","Multi-pitch systems","Trad gear placement","Sport climbing redpoint","Crack climbing technique","Overhanging movement","Dynamic climbing moves","Competition climbing skills","Big wall techniques","Ice climbing skills"]},"flexibility":{"summary":"Hip and ankle mobility support efficient hiking mechanics and reduce injury risk over long distances. Key for maintaining stride length and adapting to varied terrain.","keyComponents":["Hip flexor length","Ankle dorsiflexion range","Calf muscle flexibility","IT band mobility","Glute activation","Stride length maintenance","Step-up mobility","Descent mechanics","Trail adaptation","Late-day movement quality"],"irrelevantComponents":["Overhead shoulder mobility","Spinal rotation","Wrist flexibility","Neck mobility","Advanced yoga poses","Competition flexibility","Gymnastic ranges","Dance-specific mobility","Martial arts flexibility","Extreme hip external rotation"]}}',
'{"cardio":[{"exerciseId":"b1000000-0000-0000-0000-000000000002","exerciseName":"Sustained Zone 2 Run","graduationTarget":"12 miles continuous","whyThisTarget":"Builds the aerobic base needed for 14+ mile hiking objectives with endurance buffer."},{"exerciseId":"b1000000-0000-0000-0000-000000000003","exerciseName":"Uphill Hike with Pack","graduationTarget":"3600 ft gain in 60 minutes @ 15lb pack","whyThisTarget":"Exceeds the objective''s sustained climbing rate with pack weight for comfortable margin."}],"strength":[{"exerciseId":"b2000000-0000-0000-0000-000000000002","exerciseName":"Single-Leg Step-Down","graduationTarget":"20 controlled reps per leg","whyThisTarget":"Develops the single-leg strength and knee stability essential for long descents from Half Dome."},{"exerciseId":"b2000000-0000-0000-0000-000000000004","exerciseName":"Loaded Carry","graduationTarget":"400m @ 35lb in 10 minutes","whyThisTarget":"Builds grip endurance for the cables section and pack carrying capacity for the approach."}],"climbing_technical":[{"exerciseId":"b3000000-0000-0000-0000-000000000002","exerciseName":"Scramble Confidence Assessment","graduationTarget":"4 on 1-5 scale","whyThisTarget":"Ensures confident movement on the cables section with its Class 3 exposure and consequences."}],"flexibility":[{"exerciseId":"b4000000-0000-0000-0000-000000000001","exerciseName":"Deep Squat Hold","graduationTarget":"60 seconds","whyThisTarget":"Ensures hip and ankle mobility for efficient hiking mechanics over 14+ mile distance."}]}',
10, 'active');

-- 2. Colorado 14er Class 1-2
INSERT INTO validated_objectives (name, route, match_aliases, type, difficulty, description, summit_elevation_ft, total_gain_ft, distance_miles, duration_days, technical_grade, tags, target_scores, taglines, relevance_profiles, graduation_benchmarks, recommended_weeks, status) VALUES
('Colorado 14er (Class 1-2)', 'Standard Routes (Quandary, Elbert, Bierstadt)',   '{"14er", "fourteener", "quandary peak", "mount elbert", "bierstadt", "colorado 14er", "14er class 1", "14er class 2"}', 'hike', 'beginner', 'Standard non-technical Colorado 14ers. Typically 6-14 miles with 3000-5000ft gain above 14,000ft.', 14265, 3500, 7, 1, 'Class 1-2', '["high-altitude", "endurance"]',
'{"cardio":65,"strength":60,"climbing_technical":35,"flexibility":50}',
'{"cardio":"High altitude endurance hiking engine","strength":"Load bearing leg endurance power","climbing_technical":"Route finding scrambling confidence","flexibility":"Mobile hips for long ascents"}',
'{"cardio":{"summary":"Colorado 14ers demand sustained aerobic effort at altitude where oxygen is 40% thinner. Success requires efficient fat-burning systems and cardiovascular adaptation to reduced oxygen availability.","keyComponents":["Zone 2 aerobic base","High altitude acclimatization","Sustained uphill hiking pace","Fat oxidation efficiency","Cardiovascular oxygen transport","Respiratory muscle endurance","Hiking-specific movement patterns","Multi-hour endurance capacity","Recovery between elevation gains","Consistent pacing discipline"],"irrelevantComponents":["Sprint power","Anaerobic threshold training","High-intensity intervals","Sport-specific agility","Explosive movement patterns","Short-duration power output","Speed development","Lactate tolerance","Neuromuscular coordination","Competition pacing tactics"]},"strength":{"summary":"Leg strength and muscular endurance for sustained uphill hiking with eccentric control on descents. Core stability supports pack carrying and efficient movement over varied terrain.","keyComponents":["Hiking-specific leg endurance","Eccentric quad control","Glute activation and power","Calf strength for uphill push","Core stability under load","Hip stability and control","Ankle strength and stability","Step-up power endurance","Load-bearing capacity","Fatigue-resistant muscle systems"],"irrelevantComponents":["Maximum strength lifts","Upper body power","Olympic lifting technique","Explosive jumping ability","Heavy deadlift capacity","Bench press strength","Rotational power","Sport-specific power","Maximum grip strength","Competitive lifting metrics"]},"climbing_technical":{"summary":"Basic scrambling skills for Class 2 terrain with confident movement on loose rock and exposure. Route-finding ability and terrain assessment for safe passage.","keyComponents":["Class 2 scrambling technique","Loose rock movement","Basic exposure comfort","Route finding skills","Terrain assessment","Three-point contact discipline","Rock quality evaluation","Safe foot placement","Balance on uneven surfaces","Weather condition adaptation"],"irrelevantComponents":["Technical rope work","Advanced climbing grades","Multi-pitch systems","Protection placement","Belaying techniques","Rescue skills","Aid climbing","Big wall techniques","Ice climbing skills","Competition climbing"]},"flexibility":{"summary":"Hip and ankle mobility for efficient hiking stride and adaptation to varied terrain. Adequate flexibility prevents overuse injuries during long ascents and descents.","keyComponents":["Hip flexor mobility","Ankle dorsiflexion range","Calf flexibility","IT band mobility","Hip internal rotation","Thoracic spine mobility","Dynamic movement patterns","Stride length optimization","Terrain adaptation range","Injury prevention mobility"],"irrelevantComponents":["Extreme flexibility","Overhead mobility","Spinal hyperextension","Gymnastic ranges","Shoulder external rotation","Wrist flexibility","Advanced yoga poses","Contortion-level mobility","Performance flexibility","Sport-specific ranges"]}}',
'{"cardio":[{"exerciseId":"b1000000-0000-0000-0000-000000000002","exerciseName":"Sustained Zone 2 Run","graduationTarget":"10 miles at conversational pace","whyThisTarget":"150% overshoot of objective distance builds aerobic base for sustained high-altitude effort."},{"exerciseId":"b1000000-0000-0000-0000-000000000003","exerciseName":"Uphill Hike with Pack","graduationTarget":"5250 ft elevation gain in 60 minutes with 25lb pack","whyThisTarget":"150% overshoot of objective elevation gain ensures comfortable pace at altitude."}],"strength":[{"exerciseId":"b2000000-0000-0000-0000-000000000002","exerciseName":"Single-Leg Step-Down","graduationTarget":"20 controlled reps per leg","whyThisTarget":"Eccentric quad control essential for safe descent from 14er summits."},{"exerciseId":"b1000000-0000-0000-0000-000000000001","exerciseName":"Timed Loaded Step-Ups","graduationTarget":"450 reps in 30 minutes with 25lb pack","whyThisTarget":"Hiking-specific leg endurance for sustained uphill movement with pack weight."}],"climbing_technical":[{"exerciseId":"b3000000-0000-0000-0000-000000000002","exerciseName":"Scramble Confidence Assessment","graduationTarget":"4/5 confidence on exposed Class 3-4 terrain","whyThisTarget":"One grade above Class 2 objective ensures comfort with exposure and loose rock."}],"flexibility":[{"exerciseId":"b4000000-0000-0000-0000-000000000001","exerciseName":"Deep Squat Hold","graduationTarget":"60 seconds full-depth squat hold","whyThisTarget":"Hip and ankle mobility for efficient hiking stride and terrain adaptation."},{"exerciseId":"b4000000-0000-0000-0000-000000000003","exerciseName":"Ankle Dorsiflexion Test","graduationTarget":"4.5 inches knee-to-wall distance","whyThisTarget":"Ankle mobility prevents overuse injuries during long uphill hiking efforts."}]}',
6, 'active');

-- 3. Mt. Whitney
INSERT INTO validated_objectives (name, route, match_aliases, type, difficulty, description, summit_elevation_ft, total_gain_ft, distance_miles, duration_days, technical_grade, tags, target_scores, taglines, relevance_profiles, graduation_benchmarks, recommended_weeks, status) VALUES
('Mt. Whitney', 'Main Trail (Whitney Trail)',   '{"mt whitney", "mount whitney", "whitney", "whitney main trail", "whitney portal"}', 'hike', 'intermediate', 'Highest peak in the contiguous US via the Main Trail. 22-mile round trip with 6,100ft gain.', 14505, 6100, 22, 1, 'Class 1', '["high-altitude", "endurance", "long-day"]',
'{"cardio":75,"strength":65,"climbing_technical":25,"flexibility":45}',
'{"cardio":"All-day hiking endurance at altitude","strength":"Load-bearing legs for long descents","climbing_technical":"Basic trail navigation and balance","flexibility":"Hip and ankle mobility maintenance"}',
'{"cardio":{"summary":"Whitney demands exceptional aerobic endurance for 10-14 hours of continuous movement at altitude. The combination of distance, elevation gain, and thin air at 14,505 ft creates a massive cardiovascular challenge requiring both aerobic base and altitude adaptation.","keyComponents":["Long-duration aerobic base","High-altitude oxygen efficiency","Sustained uphill hiking power","Multi-hour energy management","Recovery between steep sections","Consistent pace maintenance","Late-day fatigue resistance","Gradual altitude acclimatization","Zone 2 aerobic development"],"irrelevantComponents":["Sprint intervals","Anaerobic power","Short burst efforts","Competition pacing","Track speed","Lactate threshold intervals","VO2 max intervals","High-intensity intervals","Explosive movements"]},"strength":{"summary":"Leg strength is crucial for the long descent and sustained uphill grinding, while core stability supports pack carrying and balance on loose trail sections. Upper body demands are minimal but some pack-carrying endurance helps.","keyComponents":["Eccentric quad strength for descent","Sustained uphill leg endurance","Ankle stability on loose rock","Core endurance for pack stability","Glute activation for power","Calf strength for sustained climbing","Hip stability for long steps"],"irrelevantComponents":["Upper body power","Heavy lifting strength","Explosive movements","Maximum strength","Overhead pressing","Pull-up strength","Grip strength","Olympic lifting","Heavy squatting","Bench pressing"]},"climbing_technical":{"summary":"The Whitney Trail is Class 1 hiking with minimal technical demands. Basic balance, route-finding, and comfort on exposed sections near the summit are sufficient.","keyComponents":["Basic balance on uneven terrain","Route-finding on cairned trail","Comfort with mild exposure","Rock-hopping technique","Switchback efficiency","Loose rock navigation"],"irrelevantComponents":["Rock climbing skills","Rope techniques","Anchor building","Scrambling ability","Multi-pitch climbing","Aid climbing","Crack climbing","Face climbing","Belaying skills","Rappelling"]},"flexibility":{"summary":"Basic mobility prevents injury and maintains efficiency over the long day. Hip flexor and ankle mobility are key for the sustained uphill grind and variable step heights.","keyComponents":["Hip flexor mobility for long steps","Ankle dorsiflexion for steep grades","Calf flexibility for descent","Basic squat mobility","IT band flexibility","Hip internal rotation"],"irrelevantComponents":["Extreme flexibility","Overhead mobility","Spinal extension","Advanced yoga poses","Shoulder flexibility","Thoracic rotation","Deep backbends","Splits","Advanced stretching","Contortion-level mobility"]}}',
'{"cardio":[{"exerciseId":"b1000000-0000-0000-0000-000000000002","exerciseName":"Sustained Zone 2 Run","graduationTarget":"15+ miles at conversational pace","whyThisTarget":"Builds the aerobic base needed for 10-14 hours of continuous movement at Whitney''s demanding pace."},{"exerciseId":"b1000000-0000-0000-0000-000000000003","exerciseName":"Uphill Hike with Pack","graduationTarget":"3000 ft gain in 60 minutes with 25lb pack","whyThisTarget":"Develops the sustained uphill power needed for Whitney''s 6,100 ft of elevation gain with training overshoot."}],"strength":[{"exerciseId":"b2000000-0000-0000-0000-000000000002","exerciseName":"Single-Leg Step-Down","graduationTarget":"20 controlled reps per leg","whyThisTarget":"Builds eccentric quad strength essential for the long, steep descent from Whitney''s summit."},{"exerciseId":"b2000000-0000-0000-0000-000000000004","exerciseName":"Loaded Carry","graduationTarget":"400m in 10 minutes with 30lb pack","whyThisTarget":"Develops core endurance and load-carrying capacity for sustained pack weight over the long day."}],"climbing_technical":[{"exerciseId":"b3000000-0000-0000-0000-000000000002","exerciseName":"Scramble Confidence Assessment","graduationTarget":"Comfort level 3 on Class 3-4 terrain","whyThisTarget":"Ensures confidence on any exposed sections near Whitney''s summit and loose rock navigation."}],"flexibility":[{"exerciseId":"b4000000-0000-0000-0000-000000000001","exerciseName":"Deep Squat Hold","graduationTarget":"60 seconds with heels flat","whyThisTarget":"Maintains hip and ankle mobility needed for variable step heights and sustained uphill hiking."}]}',
12, 'active');

-- 4. Mont Blanc
INSERT INTO validated_objectives (name, route, match_aliases, type, difficulty, description, summit_elevation_ft, total_gain_ft, distance_miles, duration_days, technical_grade, tags, target_scores, taglines, relevance_profiles, graduation_benchmarks, recommended_weeks, status) VALUES
('Mont Blanc', 'Goûter Route (Voie Normale)',   '{"mont blanc", "mont blanc normal route", "mont blanc gouter", "mont blanc from saint-gervais"}', 'mountaineering', 'advanced', 'Highest peak in the Alps via the standard Goûter Route. 2-day climb with glacier travel and altitude sickness risk.', 15781, 5200, 11, 2, 'PD', '["high-altitude", "glacier", "multi-day", "heavy-pack"]',
'{"cardio":75,"strength":70,"climbing_technical":60,"flexibility":55}',
'{"cardio":"High altitude endurance with heavy pack","strength":"Multi-day load carrying capacity","climbing_technical":"Glacier travel and crampon skills","flexibility":"Crampon mobility and recovery"}',
'{"cardio":{"summary":"Mont Blanc demands sustained aerobic power at 15,000+ feet with a heavy pack over multiple days. The cardio system must handle prolonged moderate intensity while oxygen-starved, plus recover overnight for day two performance.","keyComponents":["high altitude aerobic base","heavy pack endurance","sustained uphill hiking power","multi-day recovery capacity","zone 2 aerobic efficiency","loaded step-up endurance","altitude acclimatization response","fatigue resistance","glycogen conservation","overnight recovery ability"],"irrelevantComponents":["sprint power","anaerobic threshold","VO2 max intervals","explosive cardio","short duration intensity","sea level performance","unloaded running speed","lactate tolerance","power output bursts","race pace fitness"]},"strength":{"summary":"Multi-day heavy pack carrying over varied alpine terrain requires sustained load-bearing capacity in legs, core stability for balance on loose rock, and upper body endurance for ice axe work and self-arrest.","keyComponents":["heavy pack load carrying","multi-day strength endurance","steep terrain leg power","ankle/knee stability on loose rock","core stability with pack","ice axe grip strength","crampon walking mechanics","loaded step-up power","hip flexor endurance","postural strength with fatigue"],"irrelevantComponents":["max deadlift strength","explosive leg power","sport climbing upper body","short-term power output","unloaded movement strength","gymnastics strength","Olympic lifting","powerlifting movements","sprint mechanics","plyometric power"]},"climbing_technical":{"summary":"The Goûter Route requires basic mountaineering skills: crampon technique on glaciated terrain, ice axe use, rope travel, and confidence on exposed sections like the Goûter Couloir.","keyComponents":["crampon walking technique","ice axe self-arrest","glacier rope team travel","crevasse rescue basics","exposed ridge navigation","loose rock scrambling","alpine route finding","weather assessment","crampon-compatible boot walking","basic anchor building"],"irrelevantComponents":["advanced ice climbing","vertical rock technique","sport climbing redpoints","multi-pitch trad leading","aid climbing","big wall systems","technical rescue","advanced rope work","free climbing difficulty","bouldering power"]},"flexibility":{"summary":"Crampon walking and multi-day pack carrying create specific mobility demands. Hip flexors tighten from prolonged uphill hiking, while ankle mobility is crucial for crampon technique and preventing injury on uneven terrain.","keyComponents":["hip flexor length for step-ups","ankle dorsiflexion for crampons","calf flexibility for terrain","thoracic mobility with pack","hip mobility for step length","hamstring flexibility","recovery stretching protocols","crampon-boot walking mechanics","sleep position adaptability","morning stiffness management"],"irrelevantComponents":["extreme flexibility","gymnastics range of motion","yoga advanced poses","overhead shoulder mobility","spinal hyperextension","advanced stretching","contortion flexibility","dance mobility","martial arts flexibility","extreme hip external rotation"]}}',
'{"cardio":[{"exerciseId":"b1000000-0000-0000-0000-000000000003","exerciseName":"Uphill Hike with Pack","graduationTarget":"2000 ft/hr @ 40lb for 60 minutes","whyThisTarget":"Exceeds Mont Blanc''s sustained uphill pace requirements with multi-day pack weight"},{"exerciseId":"b1000000-0000-0000-0000-000000000001","exerciseName":"Timed Loaded Step-Ups","graduationTarget":"450 reps/30min @ 35lb","whyThisTarget":"Builds altitude-specific leg endurance with pack weight for sustained uphill travel"}],"strength":[{"exerciseId":"b2000000-0000-0000-0000-000000000004","exerciseName":"Loaded Carry","graduationTarget":"450m @ 50lb in 10 minutes","whyThisTarget":"Multi-day pack carrying capacity over alpine terrain with comfort buffer"},{"exerciseId":"b2000000-0000-0000-0000-000000000002","exerciseName":"Single-Leg Step-Down","graduationTarget":"20 controlled reps per leg","whyThisTarget":"Knee stability and control for crampon walking on uneven glacier terrain"}],"climbing_technical":[{"exerciseId":"b3000000-0000-0000-0000-000000000002","exerciseName":"Scramble Confidence Assessment","graduationTarget":"Confident 4/5 on exposed Class 3 terrain","whyThisTarget":"Comfortable movement on Goûter Couloir and summit ridge exposure"}],"flexibility":[{"exerciseId":"b4000000-0000-0000-0000-000000000001","exerciseName":"Deep Squat Hold","graduationTarget":"60-second hold","whyThisTarget":"Hip and ankle mobility for crampon walking and recovery positions"},{"exerciseId":"b4000000-0000-0000-0000-000000000003","exerciseName":"Ankle Dorsiflexion Test","graduationTarget":"4+ inches from wall","whyThisTarget":"Ankle mobility essential for proper crampon technique and injury prevention"}]}',
14, 'active');

-- 5. Mt. Rainier
INSERT INTO validated_objectives (name, route, match_aliases, type, difficulty, description, summit_elevation_ft, total_gain_ft, distance_miles, duration_days, technical_grade, tags, target_scores, taglines, relevance_profiles, graduation_benchmarks, recommended_weeks, status) VALUES
('Mt. Rainier', 'Disappointment Cleaver',   '{"mt rainier", "mount rainier", "rainier", "rainier dc", "disappointment cleaver"}', 'mountaineering', 'advanced', 'Pacific Northwest iconic volcano via the standard DC route. 2-3 day climb with glacier travel.', 14411, 9000, 16, 2, 'PD-', '["high-altitude", "glacier", "multi-day", "heavy-pack"]',
'{"cardio":75,"strength":70,"climbing_technical":35,"flexibility":45}',
'{"cardio":"Sustained power under heavy load","strength":"Load carrying endurance and stability","climbing_technical":"Basic glacier travel and ropework","flexibility":"Hip and ankle mobility maintenance"}',
'{"cardio":{"summary":"Rainier demands exceptional aerobic capacity for sustained uphill travel with heavy packs at moderate altitude over 2-3 days. The route involves 9,000 feet of elevation gain over 16 miles while carrying multi-day gear, requiring both aerobic power and muscular endurance.","keyComponents":["Heavy pack uphill endurance","Multi-hour aerobic capacity","Moderate altitude adaptation","Sustained zone 2-3 power","Recovery between climbing days","Load-bearing leg endurance","Consistent pace maintenance","Fatigue resistance under load","Extended duration effort capacity","Uphill hiking efficiency"],"irrelevantComponents":["Sprint power","Anaerobic capacity","Speed intervals","Track running economy","Flat terrain running","Unloaded endurance","High-intensity intervals","Road race pacing","Threshold power","Recovery runs"]},"strength":{"summary":"Multi-day mountaineering with heavy packs requires exceptional load-carrying capacity, leg strength for sustained uphill travel, and core stability for balance on uneven terrain. Upper body strength supports pack management and self-arrest techniques.","keyComponents":["Heavy pack carrying capacity","Uphill hiking leg strength","Core stability under load","Single-leg stability","Grip strength for tools","Load transfer efficiency","Balance with heavy pack","Step-up power endurance","Postural strength maintenance","Multi-day strength endurance"],"irrelevantComponents":["Maximum lifting strength","Power clean technique","Bench press capacity","Olympic lift proficiency","Explosive power development","Short-burst strength","Heavy deadlift maximums","Bodybuilding hypertrophy","Powerlifting technique","Sport-specific power"]},"climbing_technical":{"summary":"The Disappointment Cleaver route requires basic mountaineering skills including glacier travel, crevasse rescue awareness, and crampon technique on moderate slopes. Technical climbing skills are minimal but rope management and basic safety systems are essential.","keyComponents":["Crampon walking technique","Basic rope travel","Self-arrest proficiency","Crevasse rescue awareness","Ice axe use","Steep snow climbing","Route finding on glaciers","Basic anchor building","Team travel coordination","Weather assessment skills"],"irrelevantComponents":["Advanced rock climbing","Multi-pitch trad climbing","Sport climbing technique","Bouldering power","Aid climbing","Big wall techniques","Advanced rescue systems","Technical ice climbing","Mixed climbing","Free climbing grades"]},"flexibility":{"summary":"Multi-day mountaineering requires basic mobility maintenance to prevent injury and maintain efficient movement patterns under load. Focus is on preventing common restriction patterns rather than advanced flexibility.","keyComponents":["Hip flexor length maintenance","Ankle dorsiflexion for steep terrain","Calf flexibility for crampon use","Basic squat mobility","Shoulder mobility for pack wearing","Spinal extension maintenance","IT band length","Glute activation patterns","Daily mobility routine capacity","Recovery position access"],"irrelevantComponents":["Advanced yoga poses","Extreme range of motion","Gymnastics flexibility","Oversplit capacity","Advanced hip mobility","Contortion-level flexibility","Dance-specific mobility","Martial arts flexibility","Performance flexibility","Hypermobility training"]}}',
'{"cardio":[{"exerciseId":"b1000000-0000-0000-0000-000000000003","exerciseName":"Uphill Hike with Pack","graduationTarget":"13,500 ft gain in 60 min @ 45lb pack","whyThisTarget":"Builds 150% overshoot capacity for Rainier''s sustained 9,000ft elevation gain with heavy multi-day pack."},{"exerciseId":"b1000000-0000-0000-0000-000000000001","exerciseName":"Timed Loaded Step-Ups","graduationTarget":"600 reps in 30 min @ 45lb pack","whyThisTarget":"Develops pack-carrying leg endurance at 150% of route demands for sustained uphill travel confidence."}],"strength":[{"exerciseId":"b2000000-0000-0000-0000-000000000004","exerciseName":"Loaded Carry","graduationTarget":"500m in 10 min @ 45lb pack","whyThisTarget":"Matches actual pack weight requirements for multi-day gear carrying over varied terrain."},{"exerciseId":"b2000000-0000-0000-0000-000000000002","exerciseName":"Single-Leg Step-Down","graduationTarget":"20 controlled reps per leg","whyThisTarget":"Provides knee stability and control for steep descents with heavy pack over multiple days."}],"climbing_technical":[{"exerciseId":"b3000000-0000-0000-0000-000000000003","exerciseName":"Rope Skills Timed Test","graduationTarget":"Complete setup in 15 minutes","whyThisTarget":"Ensures competent rope handling for glacier travel and basic rescue scenarios on Rainier."}],"flexibility":[{"exerciseId":"b4000000-0000-0000-0000-000000000001","exerciseName":"Deep Squat Hold","graduationTarget":"60 second hold","whyThisTarget":"Maintains hip and ankle mobility needed for crampon walking and steep terrain navigation."},{"exerciseId":"b4000000-0000-0000-0000-000000000003","exerciseName":"Ankle Dorsiflexion Test","graduationTarget":"4 inches from wall","whyThisTarget":"Ensures adequate ankle mobility for efficient crampon technique and steep snow climbing."}]}',
14, 'active');

