INSERT INTO validated_objectives (name, route, match_aliases, type, difficulty, description, summit_elevation_ft, total_gain_ft, distance_miles, duration_days, technical_grade, tags, target_scores, taglines, relevance_profiles, graduation_benchmarks, recommended_weeks, status) VALUES
('Denali', 'West Buttress',   '{"denali", "denali west buttress", "mt mckinley", "mount mckinley"}', 'mountaineering', 'expert', 'Highest peak in North America. 17-21 day expedition with extreme altitude, cold, and heavy loads.', 20310, 13000, 32, 18, 'AD-', '["high-altitude", "glacier", "multi-day", "heavy-pack", "extreme-cold"]',
'{"cardio":85,"strength":80,"climbing_technical":35,"flexibility":45}',
'{"cardio":"Monster uphill endurance with heavy loads","strength":"Bulletproof legs and pack-carrying power","climbing_technical":"Basic glacier travel and rope skills","flexibility":"Crampon comfort and boot mobility"}',
'{"cardio":{"summary":"Denali demands exceptional aerobic capacity for 3+ weeks of sustained effort at altitude with heavy loads. The expedition requires consistent uphill hiking capacity at 60-80% max heart rate while carrying expedition weight.","keyComponents":["sustained uphill hiking with 60+ lb pack","zone 2 aerobic base for 8+ hour days","altitude adaptation and oxygen efficiency","multi-day recovery between big efforts","consistent pace maintenance under load","heavy pack step-up endurance","lactate threshold at altitude","cardiovascular efficiency in cold conditions","long-duration fat burning capacity","expedition-pace sustainability"],"irrelevantComponents":["sprint power","anaerobic intervals","short-burst cardio","running speed","agility drills","plyometric power","high-intensity intervals","race-pace efforts","technical trail running","short-distance time trials"]},"strength":{"summary":"Denali requires bulletproof leg strength for steep terrain with heavy expedition loads, plus core and grip strength for glacier travel and camp management in harsh conditions.","keyComponents":["loaded squat strength for steep terrain","single-leg stability on uneven glacier","heavy pack carrying capacity","posthole recovery leg strength","grip strength for ice axe and tools","core stability with expedition pack","step-up power with 60+ lb loads","calf strength for crampon walking","loaded carry endurance","knee stability in deep snow"],"irrelevantComponents":["upper body pressing power","pull-up strength","explosive power","Olympic lift technique","bench press capacity","short-duration max strength","gymnastic strength","sport-specific power","sprint strength","jumping power"]},"climbing_technical":{"summary":"Denali''s West Buttress requires basic mountaineering skills including glacier travel, crevasse rescue, and comfort with exposure rather than technical climbing ability.","keyComponents":["rope team glacier travel","basic crevasse rescue skills","crampon walking efficiency","ice axe self-arrest","comfort on moderate exposure","basic anchor building","rappelling competence","fixed line ascending","route finding on glacier"],"irrelevantComponents":["rock climbing technique","sport climbing skills","bouldering power","lead climbing ability","multi-pitch efficiency","crack climbing technique","face climbing balance","overhang climbing","dynamic climbing moves","competition climbing skills"]},"flexibility":{"summary":"Denali requires basic mobility for efficient movement in mountaineering boots and crampons, plus hip and ankle range of motion for variable terrain and camp tasks.","keyComponents":["ankle dorsiflexion for crampon walking","hip flexor length for steep steps","calf flexibility for boot comfort","deep squat for camp tasks","hip mobility for high steps","thoracic mobility with heavy pack","shoulder mobility for pack adjustments"],"irrelevantComponents":["extreme range of motion","gymnastic flexibility","overhead mobility","spinal hyperextension","advanced yoga poses","dynamic stretching","ballistic flexibility","competitive flexibility standards","complex movement patterns","dance-level mobility"]}}',
'{"cardio":[{"exerciseId":"b1000000-0000-0000-0000-000000000003","exerciseName":"Uphill Hike with Pack","graduationTarget":"3000 ft/hr @ 60+ lb pack","whyThisTarget":"Exceeds Denali''s steepest sections with expedition weight for safety margin."},{"exerciseId":"b1000000-0000-0000-0000-000000000001","exerciseName":"Timed Loaded Step-Ups","graduationTarget":"500 reps/30min @ 50lb","whyThisTarget":"Builds specific leg endurance for repetitive steep climbing with heavy expedition loads."}],"strength":[{"exerciseId":"b2000000-0000-0000-0000-000000000001","exerciseName":"Loaded Pack Squat","graduationTarget":"15 reps @ 60lb pack weight","whyThisTarget":"Matches expedition pack weight for steep terrain strength demands."},{"exerciseId":"b2000000-0000-0000-0000-000000000002","exerciseName":"Single-Leg Step-Down","graduationTarget":"20 per leg","whyThisTarget":"Ensures knee stability and control for uneven glacier terrain and posthole recovery."},{"exerciseId":"b2000000-0000-0000-0000-000000000004","exerciseName":"Loaded Carry","graduationTarget":"400m @ 60lb in 10min","whyThisTarget":"Matches expedition pack weight for sustained carrying capacity and grip endurance."}],"climbing_technical":[{"exerciseId":"b3000000-0000-0000-0000-000000000003","exerciseName":"Rope Skills Timed Test","graduationTarget":"15 minutes","whyThisTarget":"Ensures competent crevasse rescue and rope skills for glacier travel safety."}],"flexibility":[{"exerciseId":"b4000000-0000-0000-0000-000000000003","exerciseName":"Ankle Dorsiflexion Test","graduationTarget":"4 inches","whyThisTarget":"Provides adequate ankle mobility for efficient crampon walking and boot comfort."},{"exerciseId":"b4000000-0000-0000-0000-000000000001","exerciseName":"Deep Squat Hold","graduationTarget":"60 seconds","whyThisTarget":"Ensures hip and ankle mobility for camp tasks and variable terrain positions."}]}',
20, 'active');

