INSERT INTO validated_objectives (name, route, match_aliases, type, difficulty, description, summit_elevation_ft, total_gain_ft, distance_miles, duration_days, technical_grade, tags, target_scores, taglines, relevance_profiles, graduation_benchmarks, recommended_weeks, status) VALUES
('Grand Teton', 'Upper Exum Ridge',   '{"grand teton", "grand teton exum", "exum ridge", "upper exum"}', 'alpine_climb', 'advanced', 'Classic alpine rock climb in the Tetons. Technical 5.5 climbing with serious exposure.', 13775, 7000, 12, 1, '5.5', '["trad-climbing", "exposure", "alpine", "heavy-pack"]',
'{"cardio":75,"strength":70,"climbing_technical":65,"flexibility":55}',
'{"cardio":"Long sustained power under load","strength":"Heavy pack endurance and grip","climbing_technical":"Exposed 5.5 movement with pack","flexibility":"Hip and ankle range under fatigue"}',
'{"cardio":{"summary":"The Upper Exum demands sustained aerobic power for 7,000 feet of elevation gain over 12 miles while carrying technical gear. Long approach, technical climbing sections, and descent require consistent energy output over 10-14 hours.","keyComponents":["Sustained uphill hiking endurance","Pack-loaded cardio efficiency","Multi-hour aerobic capacity","Altitude-adjusted breathing patterns","Energy conservation pacing","Late-day fatigue resistance","Weighted step-up power","Zone 2 base development","Glycogen sparing efficiency","Recovery between pitches"],"irrelevantComponents":["Sprint intervals","Anaerobic power","Track running speed","Unweighted cardio","Short burst capacity","Road cycling","Swimming endurance","CrossFit metcons","Court sport agility","Pure VO2 max work"]},"strength":{"summary":"Technical climbing with a heavy pack demands sustained grip strength, core stability, and leg power for both uphill grinding and exposed movement. Pack weight amplifies all strength demands.","keyComponents":["Weighted pack carrying capacity","Sustained grip endurance","Core stability under load","Single-leg stability","Heavy pack squatting power","Forearm endurance","Back and shoulder stability","Weighted step-up strength","Grip security on holds","Pack-loaded balance"],"irrelevantComponents":["Bench press strength","Olympic lifting power","Bodyweight gymnastic moves","Sprint jumping ability","Unweighted pull-ups","Isolation muscle work","Power lifting maximums","Speed-focused training","Light bodyweight endurance","Mirror muscle development"]},"climbing_technical":{"summary":"The Upper Exum requires confident 5.5 movement on exposed granite while managing a pack and rope systems. Technical demands are moderate but consequences are high with significant exposure.","keyComponents":["5.5 grade climbing confidence","Exposure comfort and management","Pack-loaded movement efficiency","Basic anchor building skills","Rappelling competence","Route finding ability","Granite friction technique","Multi-pitch transitions","Rope management systems","Self-rescue fundamentals"],"irrelevantComponents":["Sport climbing redpoint ability","Advanced aid climbing","Crack climbing specialization","Bouldering power moves","Indoor climbing grades","Competition climbing skills","Free solo mentality","Big wall hauling","Ice climbing technique","Mixed climbing skills"]},"flexibility":{"summary":"Long approaches and technical moves with a pack require adequate hip and ankle mobility. Fatigue-resistant range of motion prevents injury during late-day descents and awkward positions.","keyComponents":["Hip flexor length for high steps","Ankle dorsiflexion for steep terrain","Hip external rotation for wide moves","Calf flexibility for heel hooks","Deep squat mobility","Fatigue-resistant range of motion","Pack-loaded movement patterns","Late-day flexibility maintenance","Injury prevention mobility","Recovery position comfort"],"irrelevantComponents":["Extreme flexibility ranges","Yoga advanced poses","Gymnastic flexibility","Overhead shoulder mobility","Spinal hyperextension","Advanced stretching techniques","Dance-level hip mobility","Contortion abilities","Static stretching endurance","Flexibility for speed sports"]}}',
'{"cardio":[{"exerciseId":"b1000000-0000-0000-0000-000000000003","exerciseName":"Uphill Hike with Pack","graduationTarget":"2500+ ft/hr (elite level)","whyThisTarget":"Overshoot target for 7,000 ft objective ensures comfortable sustained uphill power."},{"exerciseId":"b1000000-0000-0000-0000-000000000002","exerciseName":"Sustained Zone 2 Run","graduationTarget":"15+ miles (strong level)","whyThisTarget":"Aerobic base overshoot for 12-mile objective builds deep endurance reserves."}],"strength":[{"exerciseId":"b2000000-0000-0000-0000-000000000003","exerciseName":"Weighted Pull-Ups","graduationTarget":"5 reps @ +25lb (strong level)","whyThisTarget":"Sustained grip strength needed for 5.5 moves while managing pack weight."},{"exerciseId":"b2000000-0000-0000-0000-000000000004","exerciseName":"Loaded Carry","graduationTarget":"500m @ 70lb in 10 minutes","whyThisTarget":"Pack carrying endurance for technical terrain with climbing gear load."},{"exerciseId":"b2000000-0000-0000-0000-000000000002","exerciseName":"Single-Leg Step-Down","graduationTarget":"25 reps per leg (strong level)","whyThisTarget":"Knee stability and control for exposed descents and awkward positions."}],"climbing_technical":[{"exerciseId":"b3000000-0000-0000-0000-000000000001","exerciseName":"Top-Rope Climbing Assessment","graduationTarget":"5.7+ clean sends","whyThisTarget":"Two sub-grades above 5.5 objective ensures comfortable movement margin."},{"exerciseId":"b3000000-0000-0000-0000-000000000002","exerciseName":"Scramble Confidence Assessment","graduationTarget":"4/5 confidence rating","whyThisTarget":"High exposure comfort essential for Upper Exum''s serious consequences."}],"flexibility":[{"exerciseId":"b4000000-0000-0000-0000-000000000001","exerciseName":"Deep Squat Hold","graduationTarget":"90 seconds (strong level)","whyThisTarget":"Hip and ankle mobility for high steps and rest positions during long route."},{"exerciseId":"b4000000-0000-0000-0000-000000000003","exerciseName":"Ankle Dorsiflexion Test","graduationTarget":"5 inches (strong level)","whyThisTarget":"Ankle mobility prevents injury on steep granite and technical descents."}]}',
12, 'active');

