INSERT INTO validated_objectives (name, route, match_aliases, type, difficulty, description, summit_elevation_ft, total_gain_ft, distance_miles, duration_days, technical_grade, tags, target_scores, taglines, relevance_profiles, graduation_benchmarks, recommended_weeks, status) VALUES
('Cathedral Peak', 'Southeast Buttress',   '{"cathedral peak", "cathedral peak se buttress", "cathedral peak tuolumne"}', 'rock_climb', 'intermediate', 'Classic Tuolumne granite climb. 5-6 pitches at 5.6.', 10911, 2800, 8, 1, '5.6', '["trad-climbing", "exposure", "granite"]',
'{"cardio":65,"strength":70,"climbing_technical":75,"flexibility":60}',
'{"cardio":"Sustained mountain endurance power","strength":"Granite hauling and climbing strength","climbing_technical":"Multi-pitch trad confidence","flexibility":"High-step and jamming mobility"}',
'{"cardio":{"summary":"Cathedral Peak demands sustained aerobic power for the approach hike and multi-pitch climbing at altitude. The combination of 8-mile round-trip distance, 2800ft elevation gain, and 5-6 pitches of climbing requires excellent cardiorespiratory fitness to maintain performance throughout the long day.","keyComponents":["Sustained hiking pace at 9000-11000ft elevation","Aerobic recovery between climbing pitches","Uphill hiking endurance with approach pack","Power hiking on granite slabs and talus","Cardiovascular efficiency in thin air","All-day energy system sustainability","Heart rate control during exposure","Descent hiking quad endurance","Multi-hour activity tolerance"],"irrelevantComponents":["Sprint intervals or anaerobic power","Sea-level VO2 max performance","Running speed or race pace","Short-duration high-intensity work","Explosive movement patterns","Competition endurance metrics","Flat terrain running efficiency","Track or road racing fitness","Pure aerobic base without altitude adaptation"]},"strength":{"summary":"Cathedral Peak requires climbing-specific strength for sustained granite face climbing plus hiking strength for the long approach with gear. Upper body pulling power, core stability, and leg endurance are critical for success on this classic Tuolumne route.","keyComponents":["Sustained pulling strength for 5-6 pitches","Finger and forearm endurance on granite","Core stability during exposure","Leg strength for high steps and mantles","Pack-carrying strength on approach","Grip endurance for trad gear and holds","Shoulder stability for overhead reaches","Hip flexor strength for steep steps","Anti-fatigue strength throughout long day"],"irrelevantComponents":["Maximum deadlift or squat strength","Explosive power movements","Heavy barbell training","Bodybuilding isolation work","Olympic lifting techniques","Powerlifting competition strength","Machine-based strength training","Sport-specific strength outside climbing","Maximum single-rep efforts"]},"climbing_technical":{"summary":"Cathedral Peak''s Southeast Buttress is a classic 5.6 trad route requiring solid multi-pitch skills, gear placement confidence, and movement efficiency on Tuolumne granite. Technical competence must be well above the route grade to handle the sustained nature and commitment.","keyComponents":["Confident 5.6-5.7 trad leading ability","Multi-pitch rope management skills","Granite crack and face climbing technique","Trad gear placement and assessment","Anchor building and equalization","Rappelling and self-rescue skills","Route finding on complex terrain","Exposure comfort and mental game","Efficient climbing movement patterns"],"irrelevantComponents":["Sport climbing redpoint ability","Bouldering power moves","Aid climbing techniques","Ice or mixed climbing skills","Indoor climbing gym grades","Competition climbing skills","Advanced rescue techniques beyond self-rescue","Big wall hauling systems","Alpine ice technical skills"]},"flexibility":{"summary":"Cathedral Peak''s granite climbing demands excellent hip and ankle mobility for high steps, mantles, and crack climbing positions. The long approach also requires maintained mobility throughout the day to prevent injury and maintain climbing performance.","keyComponents":["Hip flexor mobility for high steps","Ankle dorsiflexion for granite friction","Hip external rotation for wide stances","Thoracic spine mobility for reaches","Shoulder flexibility for varied positions","Hamstring length for stemming","Calf flexibility for edging","Dynamic mobility maintenance during activity","Recovery mobility after long efforts"],"irrelevantComponents":["Extreme contortion or circus flexibility","Passive static stretching endurance","Yoga-specific poses or flows","Dance or gymnastics mobility","Overhead sports flexibility demands","Lower back hyperextension","Excessive spinal rotation","Ballistic or dynamic stretching extremes","Non-climbing specific mobility patterns"]}}',
'{"cardio":[{"exerciseId":"b1000000-0000-0000-0000-000000000002","exerciseName":"Sustained Zone 2 Run","graduationTarget":"12 miles at conversational pace","whyThisTarget":"Overshoot target builds aerobic base for 8-mile objective with elevation and climbing demands."},{"exerciseId":"b1000000-0000-0000-0000-000000000003","exerciseName":"Uphill Hike with Pack","graduationTarget":"4200 ft gain in 60 minutes with 15lb pack","whyThisTarget":"150% overshoot of 2800ft objective gain ensures strong uphill hiking power with approach gear."}],"strength":[{"exerciseId":"b2000000-0000-0000-0000-000000000003","exerciseName":"Weighted Pull-Ups","graduationTarget":"8 bodyweight pull-ups","whyThisTarget":"Sustained pulling strength needed for 5-6 pitches of 5.6 granite climbing."},{"exerciseId":"b2000000-0000-0000-0000-000000000002","exerciseName":"Single-Leg Step-Down","graduationTarget":"20 controlled reps per leg","whyThisTarget":"Eccentric leg strength for long descent and high-step climbing moves on granite."},{"exerciseId":"b2000000-0000-0000-0000-000000000004","exerciseName":"Loaded Carry","graduationTarget":"400m in 10 minutes with 25lb pack","whyThisTarget":"Grip endurance and core stability for approach hiking with climbing gear."}],"climbing_technical":[{"exerciseId":"b3000000-0000-0000-0000-000000000001","exerciseName":"Top-Rope Climbing Assessment","graduationTarget":"Clean sends of 5.8 routes","whyThisTarget":"Two sub-grades above 5.6 objective ensures confident movement on sustained granite climbing."},{"exerciseId":"b3000000-0000-0000-0000-000000000003","exerciseName":"Rope Skills Timed Test","graduationTarget":"Complete anchor-rappel-ascend sequence in 12 minutes","whyThisTarget":"Efficient rope skills essential for multi-pitch trad climbing safety and speed."}],"flexibility":[{"exerciseId":"b4000000-0000-0000-0000-000000000001","exerciseName":"Deep Squat Hold","graduationTarget":"60-second hold with heels flat","whyThisTarget":"Hip and ankle mobility needed for high steps and rest positions on granite face."},{"exerciseId":"b4000000-0000-0000-0000-000000000003","exerciseName":"Ankle Dorsiflexion Test","graduationTarget":"4.5 inches knee-to-wall distance","whyThisTarget":"Ankle mobility required for effective granite friction and edging technique."}]}',
10, 'active');

