('Trail Half Marathon', '~4,000ft Gain',   '{"trail half marathon", "trail half", "half marathon trail"}', 'trail_run', 'intermediate', 'Trail half marathon with approximately 4,000ft of elevation gain.', null, 4000, 13.1, 1, null, '["running", "endurance", "trail"]',
