'{"cardio":{"summary":"Trail half marathons demand sustained aerobic power over varied terrain with significant elevation change. The 4,000ft gain requires strong uphill hiking/running capacity while maintaining pace on flats and descents.","keyComponents":["Zone 2 aerobic base","Uphill power endurance","Lactate threshold maintenance","Downhill running control","Terrain adaptation","Sustained effort capacity","Heart rate management","Rhythm and pacing","Recovery between climbs","Metabolic efficiency"],"irrelevantComponents":["Heavy pack endurance","High altitude adaptation","Multi-day pacing","Technical rope work endurance","Cold weather efficiency","Extreme duration capacity","Anaerobic power","Sprint speed","Explosive movements","Static holds"]},"strength":{"summary":"Strength needs focus on leg durability for continuous uphill effort and eccentric control on descents. Upper body demands are minimal since no pack weight is carried.","keyComponents":["Uphill hiking power","Quad endurance","Calf endurance","Eccentric leg control","Single leg stability","Core endurance","Glute activation","Ankle stability","Fatigue resistance","Repetitive motion durability"],"irrelevantComponents":["Heavy pack capacity","Upper body pulling power","Grip strength","Overhead strength","Weighted carries","Maximum strength","Power lifting capacity","Heavy squatting","Climbing-specific strength","Cold weather gear handling"]},"climbing_technical":{"summary":"Technical demands are minimal, focusing on confident foot placement on varied trail surfaces and basic scrambling over rocks or roots.","keyComponents":["Trail foot placement","Rock hopping confidence","Root navigation","Loose surface adaptation","Basic scrambling","Terrain reading","Balance on uneven ground","Confident descending","Weather condition adaptation","Route finding basics"],"irrelevantComponents":["Rope skills","Anchor building","Belaying","Lead climbing","Trad placement","High angle techniques","Rappelling","Multi-pitch systems","Rescue techniques","Advanced scrambling"]},"flexibility":{"summary":"Hip and ankle mobility are critical for efficient stride mechanics on varied terrain and preventing injury during long efforts over elevation change.","keyComponents":["Hip flexor length","Ankle dorsiflexion","Calf flexibility","IT band mobility","Hamstring range","Hip internal rotation","Stride mechanics","Deep squat position","Dynamic movement range","Recovery positioning"],"irrelevantComponents":["Shoulder flexibility","Overhead reach","Thoracic rotation","Wrist mobility","Finger flexibility","Neck range","Spinal extension extremes","Advanced yoga poses","Extreme positions","Contortion-level flexibility"]}}',
'{"cardio":[{"exerciseId":"b1000000-0000-0000-0000-000000000002","exerciseName":"Sustained Zone 2 Run","graduationTarget":"20 miles at conversational pace","whyThisTarget":"Builds aerobic base 150% above race distance for comfortable completion."},{"exerciseId":"b1000000-0000-0000-0000-000000000003","exerciseName":"Uphill Hike with Pack","graduationTarget":"6000 feet of gain in 60 minutes with light pack","whyThisTarget":"Develops uphill power 150% above race elevation gain for strong climbing ability."}],"strength":[{"exerciseId":"b2000000-0000-0000-0000-000000000002","exerciseName":"Single-Leg Step-Down","graduationTarget":"25 controlled reps per leg","whyThisTarget":"Ensures eccentric leg control for safe and efficient downhill running."},{"exerciseId":"b2000000-0000-0000-0000-000000000005","exerciseName":"Push-Up Max Set","graduationTarget":"25 strict push-ups","whyThisTarget":"Maintains basic upper body endurance for arm swing and balance during long efforts."}],"climbing_technical":[{"exerciseId":"b3000000-0000-0000-0000-000000000002","exerciseName":"Scramble Confidence Assessment","graduationTarget":"Confidence level 3 on exposed terrain","whyThisTarget":"Ensures comfortable movement over basic rocky trail sections and stream crossings."}],"flexibility":[{"exerciseId":"b4000000-0000-0000-0000-000000000001","exerciseName":"Deep Squat Hold","graduationTarget":"45 second hold with heels flat","whyThisTarget":"Maintains hip and ankle mobility essential for efficient uphill stride mechanics."},{"exerciseId":"b4000000-0000-0000-0000-000000000003","exerciseName":"Ankle Dorsiflexion Test","graduationTarget":"4 inches knee-to-wall distance","whyThisTarget":"Ensures adequate ankle mobility for uphill running efficiency and injury prevention."}]}',
