-- 11. Colorado 14er Class 3-4
INSERT INTO validated_objectives (name, route, match_aliases, type, difficulty, description, summit_elevation_ft, total_gain_ft, distance_miles, duration_days, technical_grade, tags, target_scores, taglines, relevance_profiles, graduation_benchmarks, recommended_weeks, status) VALUES
('Colorado 14er (Class 3-4)', 'Capitol Peak / Longs Peak',   '{"capitol peak", "longs peak", "14er class 3", "14er class 4", "capitol peak knife edge"}', 'scramble', 'advanced', 'Technical Colorado 14ers with exposed scrambling (Class 3-4).', 14265, 5000, 14, 1, 'Class 3-4', '["high-altitude", "exposure", "scrambling"]',
'{"cardio":70,"strength":65,"climbing_technical":75,"flexibility":50}',
'{"cardio":"High-altitude endurance with heavy pack","strength":"Load-bearing leg power and grip","climbing_technical":"Exposed scrambling confidence and movement","flexibility":"Hip and ankle mobility for scrambling"}',
'{"cardio":{"summary":"Technical 14ers demand sustained aerobic capacity at altitude with significant elevation gain over long distances. The cardiovascular system must efficiently deliver oxygen in thin air while managing fatigue over 8-12 hour days with a loaded pack.","keyComponents":["Aerobic base for 8-12 hour efforts","High-altitude oxygen efficiency","Sustained uphill hiking endurance","Pack-weighted cardiovascular capacity","Recovery between technical sections","Mental focus under cardiovascular stress","Efficient breathing patterns at altitude","Energy system durability over long days","Cardiac output at reduced oxygen levels","Fatigue resistance for safe descents"],"irrelevantComponents":["Sprint speed and power","Anaerobic power intervals","VO2 max testing protocols","Track running mechanics","Lactate threshold training","High-intensity interval protocols","Racing tactics and strategy","Competitive running form","Speed endurance training","Neuromuscular power development"]},"strength":{"summary":"Technical 14ers require functional strength for scrambling movements, pack-carrying endurance, and stability on exposed terrain. Emphasis on eccentric leg strength for controlled descents and grip strength for handholds on rock.","keyComponents":["Loaded pack hiking strength","Eccentric leg strength for descents","Grip strength for scrambling holds","Single-leg stability and control","Core strength for pack stability","Pull-up strength for mantling moves","Functional pushing movements","Anti-fatigue strength endurance","Unilateral leg strength balance","Postural strength under load"],"irrelevantComponents":["Maximum powerlifting numbers","Explosive Olympic lifting","Bench press strength","Isolation muscle building","Bodybuilding aesthetics","Heavy bilateral squats","Sport-specific power training","Plyometric explosiveness","Maximum strength testing","Competitive lifting techniques"]},"climbing_technical":{"summary":"Class 3-4 scrambling demands confident movement on exposed rock with route-finding skills and risk management. Technical proficiency focuses on efficient movement, not maximum climbing grades.","keyComponents":["Class 3-4 scrambling fluency","Exposure comfort and management","Route-finding on scrambling terrain","Efficient handheld selection","Footwork on loose rock","Risk assessment skills","Movement efficiency under fatigue","Downclimbing confidence","Weather-appropriate movement","Emergency self-rescue basics"],"irrelevantComponents":["Advanced rope climbing grades","Complex anchor building","Multi-pitch route systems","Lead climbing protection","Advanced rescue techniques","Big wall climbing systems","Sport climbing redpoint tactics","Competition climbing training","Difficult crack climbing","Overhung climbing strength"]},"flexibility":{"summary":"Scrambling mobility focuses on hip and ankle range of motion for high steps, mantling moves, and stable footing on varied terrain. Adequate flexibility prevents injury and enables efficient movement patterns.","keyComponents":["Hip flexion for high steps","Ankle dorsiflexion for steep terrain","Hip external rotation for mantling","Thoracic spine mobility for reach","Calf flexibility for steep descents","Dynamic hip mobility","Shoulder flexibility for reach moves","Deep squat positioning","Hamstring flexibility for scrambling","Multi-planar hip movement"],"irrelevantComponents":["Extreme flexibility ranges","Advanced yoga poses","Contortion-level mobility","Gymnastics flexibility","Overhead pressing mobility","Spinal hyperextension","Advanced stretching techniques","Flexibility for aesthetics","Passive flexibility extremes","Dance-level mobility ranges"]}}',
'{"cardio":[{"exerciseId":"b1000000-0000-0000-0000-000000000003","exerciseName":"Uphill Hike with Pack","graduationTarget":"2500+ ft elevation gain in 60 minutes with 25lb pack","whyThisTarget":"Exceeds the objective''s 1000 ft/hr average pace to build comfort margin for sustained uphill hiking at altitude."},{"exerciseId":"b1000000-0000-0000-0000-000000000002","exerciseName":"Sustained Zone 2 Run","graduationTarget":"20+ mile sustained run at conversational pace","whyThisTarget":"Develops aerobic base well above the 14-mile objective distance for cardiovascular endurance throughout the long day."}],"strength":[{"exerciseId":"b2000000-0000-0000-0000-000000000002","exerciseName":"Single-Leg Step-Down","graduationTarget":"25+ controlled reps per leg on 12-inch box","whyThisTarget":"Builds eccentric leg strength and stability essential for controlled descents on loose rock and exposure."},{"exerciseId":"b2000000-0000-0000-0000-000000000003","exerciseName":"Weighted Pull-Ups","graduationTarget":"5+ reps with +25lb","whyThisTarget":"Develops upper body pulling strength needed for mantling moves and handholds during Class 3-4 scrambling."},{"exerciseId":"b2000000-0000-0000-0000-000000000004","exerciseName":"Loaded Carry","graduationTarget":"500+ meters in 10 minutes with 50lb pack","whyThisTarget":"Builds pack-carrying endurance and core stability needed for long approach hikes with overnight gear."}],"climbing_technical":[{"exerciseId":"b3000000-0000-0000-0000-000000000002","exerciseName":"Scramble Confidence Assessment","graduationTarget":"4+ on 1-5 confidence scale for exposed Class 3-4 terrain","whyThisTarget":"Ensures confident, fluid movement on the technical sections of Capitol Peak and Longs Peak without paralysis from exposure."}],"flexibility":[{"exerciseId":"b4000000-0000-0000-0000-000000000001","exerciseName":"Deep Squat Hold","graduationTarget":"90+ second hold with heels flat","whyThisTarget":"Provides hip and ankle mobility needed for high steps and stable positioning during scrambling moves."},{"exerciseId":"b4000000-0000-0000-0000-000000000003","exerciseName":"Ankle Dorsiflexion Test","graduationTarget":"5+ inches knee-to-wall distance","whyThisTarget":"Ensures adequate ankle flexibility for steep terrain navigation and stable foot placement on rock."}]}',
12, 'active');

-- 12. Enchantments Traverse
INSERT INTO validated_objectives (name, route, match_aliases, type, difficulty, description, summit_elevation_ft, total_gain_ft, distance_miles, duration_days, technical_grade, tags, target_scores, taglines, relevance_profiles, graduation_benchmarks, recommended_weeks, status) VALUES
('Enchantments Traverse', 'Snow Lakes to Stuart Lake',   '{"enchantments", "enchantments traverse", "enchantment lakes"}', 'hike', 'intermediate', 'Epic point-to-point traverse through the Enchantment Lakes basin. 18 miles with 4,500ft gain.', 7800, 4500, 18, 1, 'Class 1-2', '["endurance", "long-day", "alpine-lakes"]',
'{"cardio":70,"strength":60,"climbing_technical":25,"flexibility":50}',
'{"cardio":"All-day endurance hiking engine","strength":"Load bearing hiking strength","climbing_technical":"Basic scrambling confidence only","flexibility":"Hiking mobility and recovery"}',
'{"cardio":{"summary":"The Enchantments Traverse demands exceptional aerobic endurance for 18 miles of sustained hiking with significant elevation gain. This is a pure cardiovascular test requiring all-day steady-state energy production with loaded pack weight.","keyComponents":["sustained aerobic base","hiking-specific endurance","loaded pack tolerance","uphill climbing efficiency","fatigue resistance over 8-12 hours","zone 2 heart rate sustainability","leg turnover endurance","elevation gain capacity","multi-hour energy management","late-day performance maintenance"],"irrelevantComponents":["anaerobic power","sprint intervals","VO2 max efforts","high-intensity intervals","lactate threshold work","explosive movements","short-burst cardio","cycling-specific fitness","swimming endurance","power endurance climbing"]},"strength":{"summary":"Moderate strength demands focused on load-bearing hiking capacity and leg endurance. Primary need is supporting body weight plus pack over extended terrain with thousands of steps and elevation changes.","keyComponents":["loaded pack carrying","uphill hiking power","leg endurance strength","knee stability on descent","core stability with pack","ankle strength on uneven terrain","hip stability for long distances","grip strength for trekking poles","postural strength with load","step-up power"],"irrelevantComponents":["maximum strength lifts","explosive power","upper body pulling strength","overhead pressing","Olympic lifting","heavy deadlifting","bench pressing","advanced core gymnastics","weighted chin-ups","high-intensity strength circuits"]},"climbing_technical":{"summary":"Minimal technical demands with occasional Class 2 scrambling over rock slabs and boulder fields. Basic movement confidence on easy terrain is sufficient.","keyComponents":["Class 2 scrambling comfort","rock slab confidence","basic route finding","three-point contact movement","balance on uneven surfaces","basic rock reading","exposure tolerance","efficient movement patterns"],"irrelevantComponents":["rope skills","belaying technique","anchor building","rappelling","multi-pitch systems","crack climbing","face climbing technique","advanced route reading","rescue skills","technical gear placement"]},"flexibility":{"summary":"Standard hiking mobility needs for efficient movement and recovery. Focus on hip, ankle, and posterior chain flexibility to maintain stride efficiency over long distances.","keyComponents":["hip flexor mobility","ankle dorsiflexion","hamstring flexibility","calf flexibility","hip internal rotation","thoracic spine mobility","IT band mobility","squat depth","stride efficiency mobility","recovery stretching"],"irrelevantComponents":["extreme flexibility","gymnastic-level mobility","overhead shoulder flexibility","advanced yoga poses","contortion-level stretching","competitive flexibility","dance-specific mobility","martial arts flexibility","circus flexibility","hypermobility training"]}}',
'{"cardio":[{"exerciseId":"b1000000-0000-0000-0000-000000000002","exerciseName":"Sustained Zone 2 Run","graduationTarget":"12-15 miles at conversational pace","whyThisTarget":"Builds the sustained aerobic base needed for 18-mile hiking objective with 50% training overshoot."},{"exerciseId":"b1000000-0000-0000-0000-000000000003","exerciseName":"Uphill Hike with Pack","graduationTarget":"3000+ ft gain in 60 minutes with day pack","whyThisTarget":"Prepares for 4,500 ft elevation gain with 150% overshoot to build comfort buffer."}],"strength":[{"exerciseId":"b2000000-0000-0000-0000-000000000002","exerciseName":"Single-Leg Step-Down","graduationTarget":"20 controlled reps per leg","whyThisTarget":"Builds knee stability and eccentric strength needed for long descents in the traverse."},{"exerciseId":"b2000000-0000-0000-0000-000000000004","exerciseName":"Loaded Carry","graduationTarget":"450m in 10 minutes with 40lb pack","whyThisTarget":"Develops load-bearing endurance for day-long pack carrying over 18 miles."}],"climbing_technical":[{"exerciseId":"b3000000-0000-0000-0000-000000000002","exerciseName":"Scramble Confidence Assessment","graduationTarget":"3-4 on confidence scale","whyThisTarget":"Ensures comfortable movement on Class 2 terrain with occasional exposure in the basin."}],"flexibility":[{"exerciseId":"b4000000-0000-0000-0000-000000000001","exerciseName":"Deep Squat Hold","graduationTarget":"60 seconds","whyThisTarget":"Maintains hip and ankle mobility needed for varied terrain and efficient hiking stride."},{"exerciseId":"b4000000-0000-0000-0000-000000000003","exerciseName":"Ankle Dorsiflexion Test","graduationTarget":"4+ inches knee-to-wall distance","whyThisTarget":"Ensures adequate ankle mobility for uphill hiking efficiency and injury prevention."}]}',
8, 'active');

-- 13. John Muir Trail
INSERT INTO validated_objectives (name, route, match_aliases, type, difficulty, description, summit_elevation_ft, total_gain_ft, distance_miles, duration_days, technical_grade, tags, target_scores, taglines, relevance_profiles, graduation_benchmarks, recommended_weeks, status) VALUES
('John Muir Trail', 'Happy Isles to Whitney',   '{"john muir trail", "jmt", "john muir", "jmt thru-hike"}', 'backpacking', 'advanced', 'Iconic 211-mile thru-hike from Yosemite to Mt Whitney summit. 14-21 days.', 14505, 47000, 211, 18, 'Class 1', '["multi-day", "heavy-pack", "high-altitude", "endurance"]',
'{"cardio":85,"strength":75,"climbing_technical":35,"flexibility":65}',
'{"cardio":"Multi-week high altitude endurance engine","strength":"Heavy pack durability over terrain","climbing_technical":"Basic trail navigation confidence","flexibility":"Joint durability for repetitive motion"}',
'{"cardio":{"summary":"The JMT demands exceptional aerobic capacity for 18 days of continuous hiking with significant daily elevation gains at high altitude. Your engine must sustain moderate effort for 8-12 hours daily while carrying a heavy pack in oxygen-depleted environments.","keyComponents":["Zone 2 aerobic base for all-day sustainability","High altitude oxygen efficiency above 10,000 feet","Heavy pack carrying endurance","Multi-day recovery between long efforts","Uphill hiking power at sustained grades","Glycogen management over extended periods","Heat regulation during long exertion","Mental endurance for repetitive movement","Daily energy output consistency","Cardiovascular efficiency with load"],"irrelevantComponents":["Sprint power or speed","Short anaerobic intervals","Competition pacing tactics","VO2 max optimization","Running economy at fast paces","Track workout intervals","Race-specific lactate threshold","Explosive cardiovascular power","Short recovery protocols","Peak heart rate training"]},"strength":{"summary":"Multi-week backpacking requires exceptional strength endurance in legs, core, and carrying muscles. Focus on durability under load rather than peak strength, with emphasis on injury prevention over rough terrain.","keyComponents":["Quad and glute endurance for sustained uphills","Eccentric leg strength for long descents","Core stability under asymmetric pack load","Carrying capacity for multi-day food/gear","Single-leg stability on uneven terrain","Hip flexor strength for high steps","Calf endurance for sustained grades","Upper back endurance for pack support","Grip strength for trekking poles","Anti-fatigue muscular resilience"],"irrelevantComponents":["Maximum lifting capacity","Olympic lifting technique","Powerlifting competition moves","Explosive power development","Upper body mass building","Bench press strength","Short-duration max efforts","Bodybuilding isolation work","Advanced gymnastic movements","Competition lifting protocols"]},"climbing_technical":{"summary":"The JMT is primarily Class 1 hiking with minimal technical demands. Basic scrambling confidence and navigation skills are sufficient, with emphasis on route-finding and basic mountain safety.","keyComponents":["Map and compass navigation basics","Route-finding on established trails","Basic scrambling on loose rock","Stream crossing techniques","Weather assessment for safety","Basic first aid in remote areas","Equipment management and care","Leave No Trace principles","Emergency signaling knowledge"],"irrelevantComponents":["Advanced rock climbing technique","Multi-pitch climbing systems","Technical rescue skills","Ice climbing proficiency","Advanced rope work","Big wall climbing systems","Sport climbing tactics","Traditional climbing protection","Alpine climbing techniques","Competition climbing skills"]},"flexibility":{"summary":"Long-distance backpacking demands joint mobility for repetitive hiking motion and injury prevention. Focus on hip, ankle, and thoracic mobility to maintain efficient gait and prevent overuse injuries over 200+ miles.","keyComponents":["Hip flexor mobility for high steps","Ankle dorsiflexion for steep descents","Thoracic rotation under pack load","Hamstring flexibility for varied terrain","Calf flexibility for sustained grades","IT band mobility for lateral stability","Shoulder mobility for pack adjustment","Deep squat mobility for camp tasks","Spinal extension to counter pack posture"],"irrelevantComponents":["Extreme range of motion","Gymnastic-level flexibility","Advanced yoga poses","Overhead mobility beyond basic","Competition-level flexibility","Dance or martial arts mobility","Hypermobility training","Advanced stretching protocols","Contortion-level ranges","Sport-specific flexibility beyond hiking"]}}',
'{"cardio":[{"exerciseId":"b1000000-0000-0000-0000-000000000002","exerciseName":"Sustained Zone 2 Run","graduationTarget":"15+ miles at conversational pace","whyThisTarget":"Builds the aerobic base needed for 8-12 hour daily hiking efforts at sustainable intensity."},{"exerciseId":"b1000000-0000-0000-0000-000000000003","exerciseName":"Uphill Hike with Pack","graduationTarget":"3000+ ft gain in 60 minutes with 40lb pack","whyThisTarget":"Prepares for JMT''s demanding daily elevation gains while carrying multi-day supplies."}],"strength":[{"exerciseId":"b2000000-0000-0000-0000-000000000002","exerciseName":"Single-Leg Step-Down","graduationTarget":"25+ controlled reps per leg","whyThisTarget":"Develops eccentric leg strength essential for the JMT''s long, knee-punishing descents."},{"exerciseId":"b2000000-0000-0000-0000-000000000004","exerciseName":"Loaded Carry","graduationTarget":"500+ meters in 10 minutes with 50lb","whyThisTarget":"Builds carrying endurance for the multi-day pack loads required on the JMT."}],"climbing_technical":[{"exerciseId":"b3000000-0000-0000-0000-000000000002","exerciseName":"Scramble Confidence Assessment","graduationTarget":"4+ on 1-5 scale","whyThisTarget":"Ensures confidence on occasional loose rock sections and stream crossings found on the JMT."}],"flexibility":[{"exerciseId":"b4000000-0000-0000-0000-000000000001","exerciseName":"Deep Squat Hold","graduationTarget":"90+ seconds","whyThisTarget":"Maintains hip and ankle mobility crucial for varied terrain and daily camp tasks over 18 days."},{"exerciseId":"b4000000-0000-0000-0000-000000000003","exerciseName":"Ankle Dorsiflexion Test","graduationTarget":"5+ inches knee-to-wall distance","whyThisTarget":"Prevents calf tightness and Achilles issues during the JMT''s sustained uphill and downhill sections."}]}',
14, 'active');

