INSERT INTO validated_objectives (name, route, match_aliases, type, difficulty, description, summit_elevation_ft, total_gain_ft, distance_miles, duration_days, technical_grade, tags, target_scores, taglines, relevance_profiles, graduation_benchmarks, recommended_weeks, status) VALUES
('Kilimanjaro', 'Machame Route',   '{"kilimanjaro", "kili", "kilimanjaro machame", "mount kilimanjaro"}', 'hike', 'intermediate', 'Highest peak in Africa via the popular Machame Route. 6-7 day trek to 19,341ft.', 19341, 13000, 37, 7, 'Class 1', '["high-altitude", "multi-day", "endurance"]',
'{"cardio":80,"strength":70,"climbing_technical":25,"flexibility":60}',
'{"cardio":"Multi-day altitude endurance machine","strength":"Pack-carrying leg durability","climbing_technical":"Class 1 scrambling confidence","flexibility":"Hip and ankle mobility"}',
'{"cardio":{"summary":"Kilimanjaro demands exceptional aerobic endurance for 6+ hour hiking days at extreme altitude where oxygen is 50% of sea level. The cardiovascular system must sustain moderate effort for days while adapting to progressive altitude stress.","keyComponents":["Zone 2 aerobic base","Multi-hour endurance","Altitude adaptation capacity","Pack-carrying endurance","Uphill hiking stamina","Recovery between long days","Steady-state energy systems","Cardiovascular efficiency","Sustained moderate intensity","Fatigue resistance over days"],"irrelevantComponents":["Sprint speed","Anaerobic power","VO2 max intervals","High-intensity intervals","Lactate threshold work","Short burst efforts","Speed endurance","Neuromuscular power","Explosive cardio","Race pace training"]},"strength":{"summary":"Kilimanjaro requires tremendous leg strength and endurance to carry a pack uphill for 6+ hours daily over a week. Core stability and grip strength support pack carrying and trekking pole use.","keyComponents":["Loaded pack carrying","Uphill hiking strength","Leg endurance under load","Quadriceps durability","Glute strength for ascent","Calf strength for terrain","Core stability with pack","Grip strength for poles","Hip stability on uneven ground","Eccentric control on descent"],"irrelevantComponents":["Explosive power","Olympic lift variations","Bench press strength","Overhead pressing","Pull-up strength","Deadlift max","Sprint mechanics","Jumping ability","Upper body hypertrophy","Powerlifting movements"]},"climbing_technical":{"summary":"Kilimanjaro is pure Class 1 hiking with no technical climbing required. The only technical element is basic scrambling confidence on loose rock and steep terrain.","keyComponents":["Loose rock navigation","Steep terrain confidence","Basic scrambling","Terrain assessment","Safe foot placement","Balance on uneven ground","Route finding on trail","Scree slope technique","Basic self-arrest awareness","Weather decision making"],"irrelevantComponents":["Rock climbing technique","Rope skills","Belaying systems","Anchor building","Multi-pitch systems","Crack climbing","Face climbing","Sport climbing","Traditional climbing","Alpine climbing systems"]},"flexibility":{"summary":"Good hip and ankle mobility prevents injury during long hiking days and helps with the deep knee bends required when navigating rocky terrain with a heavy pack.","keyComponents":["Hip flexor mobility","Ankle dorsiflexion","Deep squat position","Calf flexibility","Achilles mobility","Hip external rotation","Knee tracking alignment","IT band mobility","Glute activation","Dynamic movement patterns"],"irrelevantComponents":["Shoulder mobility","Thoracic spine rotation","Overhead reach","Spinal extension","Hamstring flexibility","Lat flexibility","Wrist mobility","Neck mobility","Advanced yoga poses","Extreme range of motion"]}}',
'{"cardio":[{"exerciseId":"b1000000-0000-0000-0000-000000000003","exerciseName":"Uphill Hike with Pack","graduationTarget":"3000 ft gain/hr @ 25lb pack","whyThisTarget":"150% overshoot of Kilimanjaro''s daily 1800-2000ft gain builds altitude endurance buffer."},{"exerciseId":"b1000000-0000-0000-0000-000000000002","exerciseName":"Sustained Zone 2 Run","graduationTarget":"12 miles continuous","whyThisTarget":"150% of daily 8-mile hiking distance builds aerobic base for multi-day effort."}],"strength":[{"exerciseId":"b2000000-0000-0000-0000-000000000002","exerciseName":"Single-Leg Step-Down","graduationTarget":"25 controlled reps per leg","whyThisTarget":"Ensures eccentric quad control for steep descents with heavy pack over multiple days."},{"exerciseId":"b2000000-0000-0000-0000-000000000004","exerciseName":"Loaded Carry","graduationTarget":"500m @ 25lb in 10 minutes","whyThisTarget":"Matches expected Kilimanjaro pack weight for sustained carrying endurance."}],"climbing_technical":[{"exerciseId":"b3000000-0000-0000-0000-000000000002","exerciseName":"Scramble Confidence Assessment","graduationTarget":"4 on 1-5 scale","whyThisTarget":"Builds confidence buffer above Class 1 requirements for loose rock and exposure."}],"flexibility":[{"exerciseId":"b4000000-0000-0000-0000-000000000001","exerciseName":"Deep Squat Hold","graduationTarget":"90 second hold","whyThisTarget":"Enables deep knee bends for navigating rocky terrain and prevents hip tightness from long hiking days."},{"exerciseId":"b4000000-0000-0000-0000-000000000003","exerciseName":"Ankle Dorsiflexion Test","graduationTarget":"5 inches knee-to-wall distance","whyThisTarget":"Prevents Achilles issues from repetitive uphill hiking and enables proper foot placement on steep terrain."}]}',
10, 'active');

