INSERT INTO validated_objectives (name, route, match_aliases, type, difficulty, description, summit_elevation_ft, total_gain_ft, distance_miles, duration_days, technical_grade, tags, target_scores, taglines, relevance_profiles, graduation_benchmarks, recommended_weeks, status) VALUES
('Tour du Mont Blanc', 'Full Circuit (Counter-clockwise)',   '{"tour du mont blanc", "tmb", "tmb trek", "tour mont blanc"}', 'backpacking', 'intermediate', 'Classic 105-mile circuit around the Mont Blanc massif. 10-12 days with 32,000ft total gain.', 8900, 32000, 105, 11, 'Class 1', '["multi-day", "heavy-pack", "endurance", "european-alps"]',
'{"cardio":80,"strength":75,"climbing_technical":30,"flexibility":60}',
'{"cardio":"Multi-day pack endurance engine","strength":"Heavy pack durability and stability","climbing_technical":"Trail navigation and basic scrambling","flexibility":"Lower body mobility for recovery"}',
'{"cardio":{"summary":"The TMB demands exceptional aerobic endurance for 11 consecutive days of 8-12 hour hiking with significant daily elevation gain. Your aerobic system must function efficiently while carrying a loaded pack across varied European terrain at moderate altitude.","keyComponents":["Multi-day aerobic endurance","Heavy pack cardiovascular efficiency","Sustained uphill hiking capacity","Daily recovery between efforts","Moderate altitude adaptation","Long-duration fat oxidation","Consistent daily output over 11 days","Zone 2 aerobic base development","Loaded pack step-up endurance"],"irrelevantComponents":["Sprint power","VO2 max intervals","Anaerobic threshold work","Short burst cardio","High-intensity interval training","Track speed work","Bike-specific endurance","Swimming endurance","Explosive cardio movements","Competition pacing"]},"strength":{"summary":"Strength focus centers on durability for carrying a multi-day pack across varied terrain while maintaining joint stability and preventing injury over 105 miles. Lower body strength and grip endurance are critical for consistent daily performance.","keyComponents":["Heavy pack carrying capacity","Lower body muscular endurance","Knee and ankle stability under load","Hip durability for long descents","Grip strength for trekking poles","Core stability with pack weight","Leg strength for steep ascents","Posterior chain endurance","Single-leg stability on uneven terrain"],"irrelevantComponents":["Maximum strength lifts","Olympic lifting movements","Upper body power","Explosive jumping ability","Heavy deadlifts","Bench press strength","Short-duration max efforts","Powerlifting movements","Sport-specific power","Gymnastic strength skills"]},"climbing_technical":{"summary":"Technical demands are minimal on the TMB''s well-marked trails, requiring only basic scrambling confidence and route-finding skills. Focus is on efficient movement over varied terrain rather than technical climbing ability.","keyComponents":["Basic scrambling confidence","Trail route-finding","Efficient movement on loose terrain","River crossing technique","Weather assessment skills","Map and compass navigation","Terrain evaluation","Safe descent techniques"],"irrelevantComponents":["Rock climbing grades","Advanced rope skills","Multi-pitch climbing","Ice climbing technique","Technical rescue skills","Advanced anchor building","Sport climbing efficiency","Bouldering power","Aid climbing technique","Mixed climbing skills"]},"flexibility":{"summary":"Mobility requirements focus on maintaining lower body function across 11 days of repetitive hiking motion. Hip flexors, ankles, and posterior chain must stay functional for daily recovery and injury prevention.","keyComponents":["Hip flexor mobility for long days","Ankle dorsiflexion for steep terrain","Posterior chain flexibility","Daily recovery stretching routine","IT band and lateral hip mobility","Calf and Achilles flexibility","Lower back mobility with pack weight","Squat depth maintenance"],"irrelevantComponents":["Shoulder overhead mobility","Thoracic spine rotation","Hamstring extreme flexibility","Advanced yoga poses","Sport-specific flexibility","Dynamic stretching routines","Upper body mobility work","Gymnastic flexibility","Competition-level ranges of motion","Advanced movement patterns"]}}',
'{"cardio":[{"exerciseId":"b1000000-0000-0000-0000-000000000003","exerciseName":"Uphill Hike with Pack","graduationTarget":"3000 ft/hr @ 35lb pack","whyThisTarget":"Builds capacity well above TMB''s average 2000 ft/hr daily gain requirement for comfortable multi-day performance."},{"exerciseId":"b1000000-0000-0000-0000-000000000001","exerciseName":"Timed Loaded Step-Ups","graduationTarget":"600 reps/30min @ 35lb","whyThisTarget":"Develops heavy pack endurance beyond what''s needed for TMB''s sustained daily hiking demands."}],"strength":[{"exerciseId":"b2000000-0000-0000-0000-000000000004","exerciseName":"Loaded Carry","graduationTarget":"600m @ 40lb in 10min","whyThisTarget":"Matches the multi-day pack weight and duration demands of TMB hiking."},{"exerciseId":"b2000000-0000-0000-0000-000000000002","exerciseName":"Single-Leg Step-Down","graduationTarget":"25 reps per leg","whyThisTarget":"Ensures knee stability for TMB''s extensive downhill sections with pack weight."}],"climbing_technical":[{"exerciseId":"b3000000-0000-0000-0000-000000000002","exerciseName":"Scramble Confidence Assessment","graduationTarget":"4/5 confidence rating","whyThisTarget":"TMB has minimal scrambling but confident movement on loose terrain prevents falls."}],"flexibility":[{"exerciseId":"b4000000-0000-0000-0000-000000000001","exerciseName":"Deep Squat Hold","graduationTarget":"90 seconds","whyThisTarget":"Ensures hip and ankle mobility for TMB''s daily recovery and tent camping positions."},{"exerciseId":"b4000000-0000-0000-0000-000000000002","exerciseName":"Hip Flexor Stretch Assessment","graduationTarget":"4/5 rating","whyThisTarget":"Prevents hip flexor tightness from TMB''s repetitive uphill hiking motion over 11 days."}]}',
10, 'active');
